import React, { useState } from 'react';

const CaseDetail: React.FC = () => {
    const [opening, setOpening] = useState(false);
    const openCase = async () => {
        setOpening(true);
        try {
            // временно
            setOpening(false);
        } catch (err) {
            alert(err);
            setOpening(false);
        }
    };
    return <div>Case Detail</div>;
};

export default CaseDetail;
